        "Prestaciones",
        "Sueldo Mensual Base",
        ...percepcionHeaders,
        "Total Percepciones",
        "Salario Diario",
        "SDI",
        "IMSS Patronal",
        "Retiro Pat.",
        "C y V Pat.",
        "INFONAVIT Pat.",
        "Aguinaldo Mensual",
        "Prima Vac. Mensual",
        "Costo ISN Mensual",
        "Costo Total Empresa",
        "Factor de Costo",
