export type BenefitSchemeType = 'ley' | 'antes1991' | 'gerentes';

export const BENEFIT_SCHEMES: { [key in BenefitSchemeType]: { name: string; getAguinaldoDays: (years: number) => number; getPrimaVacacionalPct: (years: number) => number; } } = {
  ley: {
    name: 'Ley',
    getAguinaldoDays: () => 15,
    getPrimaVacacionalPct: () => 0.25,
  },
  antes1991: {
    name: 'Antes de 1991',
    getAguinaldoDays: (years: number) => {
      const y = Math.floor(years);
      if (y < 1) return 0;
      if (y === 1) return 16;
      if (y <= 3) return 21;
      if (y === 4) return 26;
      return 31;
    },
    getPrimaVacacionalPct: (years: number) => {
      const y = Math.floor(years);
      if (y < 1) return 0;
      if (y <= 4) return 0.30;
      return 0.35;
    },
  },
  gerentes: {
    name: 'Gerentes',
    getAguinaldoDays: (years: number) => {
      const y = Math.floor(years);
      if (y < 1) return 0;
      if (y <= 3) return 22;
      if (y === 4) return 27;
      return 32;
    },
    getPrimaVacacionalPct: (years: number) => {
      const y = Math.floor(years);
      if (y < 1) return 0;
      if (y <= 4) return 0.35;
      return 0.40;
    },
  },
};


