import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { ConfigPanel } from './components/ConfigPanel';
import { ResultsTable } from './components/ResultsTable';
import { InfoIcon, ResetIcon, DownloadIcon } from './components/icons';
import { DEFAULT_UMA, DEFAULT_WORK_RISK, DEFAULT_ISN, SDI_CAP_MULTIPLIER, DAYS_IN_MONTH, DAYS_IN_YEAR, IMSS_RATES, INFONAVIT_RATE_PCT, BENEFIT_SCHEMES, BenefitSchemeType, ISR_MONTHLY_TABLE, SUBSIDY_MONTHLY_TABLE, CESANTIA_VEJEZ_RATES_2026 } from './constants';
import type { ParsedData, CalculationResult } from './types';
import { CalculationDatePanel } from './components/CalculationDatePanel';
import { DataTablesPanel } from './components/DataTablesPanel';

function App() {
    const [rawText, setRawText] = useState('');
    const [uma, setUma] = useState(DEFAULT_UMA);
    const [workRisk, setWorkRisk] = useState(DEFAULT_WORK_RISK);
    const [isn, setIsn] = useState(DEFAULT_ISN);
    const [employeeIdCol, setEmployeeIdCol] = useState<number>(0);
    const [employeeNameCol, setEmployeeNameCol] = useState<number>(1);
    const [hireDateCol, setHireDateCol] = useState<number>(2);
    const [dailySalaryCol, setDailySalaryCol] = useState<number>(3);
    const [configSaved, setConfigSaved] = useState(false);
    const [percepcionesLayout, setPercepcionesLayout] = useState<'vertical' | 'horizontal'>('vertical');
    const [results, setResults] = useState<CalculationResult[]>([]);
    const [calculationDate, setCalculationDate] = useState(new Date());


    useEffect(() => {
        const savedConfigRaw = localStorage.getItem('payrollConfig');
        if (savedConfigRaw) {
            try {
                const savedConfig = JSON.parse(savedConfigRaw);
                if (typeof savedConfig.uma === 'number') setUma(savedConfig.uma);
                if (typeof savedConfig.workRisk === 'number') setWorkRisk(savedConfig.workRisk);
                if (typeof savedConfig.isn === 'number') setIsn(savedConfig.isn);
            } catch (error) {
                console.error("Failed to parse saved config from localStorage:", error);
                localStorage.removeItem('payrollConfig');
            }
        }
    }, []);

    const parsedData: ParsedData = useMemo(() => {
        if (!rawText.trim()) return { headers: [], rows: [] };
        const rows = rawText.trim().split('\n').map(row => row.split('\t'));
        const headers = rows[0] || [];
        const dataRows = rows.slice(1);
        return { headers, rows: dataRows };
    }, [rawText]);

    const getVacationDaysForSeniority = (years: number): number => {
        // For SDI calculation, we use the vacation days corresponding to the current year of service an employee is in.
        // This ensures the integration factor is correct from day one and updates on each anniversary.
        if (years < 0) return 0; // Seniority cannot be negative.

        // An employee with 0 to 0.99 years is in their 1st year of service.
        // An employee with 1.0 to 1.99 years is in their 2nd year of service, and so on.
        const currentYearOfService = Math.floor(years) + 1;

        // Per Mexican Labor Law (LFT Art. 76):
        // Year 1: 12 days. Increases by 2 days per year up to year 5 (20 days).
        if (currentYearOfService <= 5) {
            // This formula covers years 1-5: 10 + (1*2)=12, 10 + (2*2)=14, ..., 10 + (5*2)=20
            return 10 + (currentYearOfService * 2);
        }

        // From the 6th year, it increases by 2 days for every 5 years of service.
        // Years 6-10 -> 22 days. Years 11-15 -> 24 days etc.
        const fiveYearBlocks = Math.floor((currentYearOfService - 1) / 5);
        return 20 + (fiveYearBlocks * 2);
    };

    const percepcionColumns = useMemo(() => {
        const requiredCols = new Set([employeeIdCol, employeeNameCol, hireDateCol, dailySalaryCol]);
        if (parsedData.headers.length === 0) return [];
        return parsedData.headers
            .map((_, i) => i)
            .filter(i => !requiredCols.has(i));
    }, [parsedData.headers, employeeIdCol, employeeNameCol, hireDateCol, dailySalaryCol]);

    const percepcionHeaders = useMemo(() => 
        percepcionColumns.map(i => parsedData.headers[i]), 
        [percepcionColumns, parsedData.headers]
    );

    const calculateEmployeeResult = useCallback((
        row: (string | number)[],
        benefitScheme: BenefitSchemeType,
        calcDate: Date
    ): CalculationResult | null => {

        const getCesantiaVejezRate = (sdi: number, umaValue: number): number => {
            const sdiInUma = sdi / umaValue;
            if (sdiInUma <= 1.00) return 3.15;
            if (sdiInUma <= 1.50) return 3.68;
            if (sdiInUma <= 2.00) return 4.85;
            if (sdiInUma <= 2.50) return 5.56;
            if (sdiInUma <= 3.00) return 6.03;
            if (sdiInUma <= 3.50) return 6.36;
            if (sdiInUma <= 4.00) return 6.61;
            return 7.51;
        };

        const employeeId = String(row[employeeIdCol] || `row-${Math.random()}`);
        const employeeName = String(row[employeeNameCol] || 'N/A');
        const hireDateStr = String(row[hireDateCol] || '');
        const salarioDiario = parseFloat(String(row[dailySalaryCol] || '0').replace(/[^0-9.-]+/g, ""));

        if (!hireDateStr || isNaN(salarioDiario) || salarioDiario <= 0) {
            return null;
        }

        const parts = hireDateStr.match(/(\d+)/g);
        let hireDate: Date | null = null;
        if(parts && parts.length === 3) {
            const [p1, p2, p3] = parts.map(Number);
            if (p1 > 0 && p1 <= 31 && p2 > 0 && p2 <= 12 && p3 > 1900) {
                hireDate = new Date(p3, p2 - 1, p1);
            } else if (p1 > 1900 && p2 > 0 && p2 <= 12 && p3 > 0 && p3 <= 31) {
                hireDate = new Date(p1, p2 - 1, p3);
            }
        }
        if (!hireDate || isNaN(hireDate.getTime())) {
            hireDate = new Date(hireDateStr);
        }
        if (!hireDate || isNaN(hireDate.getTime())) return null;

        const schemeConfig = BENEFIT_SCHEMES[benefitScheme];
        const yearsOfService = (calcDate.getTime() - hireDate.getTime()) / (1000 * 60 * 60 * 24 * 365.25);
        const vacationDays = getVacationDaysForSeniority(yearsOfService);
        const aguinaldoDays = schemeConfig.getAguinaldoDays(yearsOfService);
        const primaVacacionalPct = schemeConfig.getPrimaVacacionalPct(yearsOfService);

        const factorIntegracion = 1 + (aguinaldoDays / DAYS_IN_YEAR) + (vacationDays * primaVacacionalPct / DAYS_IN_YEAR);

        const percepcionesDetalladas: { name: string; value: number }[] = [];
        const totalOtrasPercepciones = percepcionColumns.reduce((acc, colIndex) => {
            const value = row[colIndex];
            const numValue = typeof value === 'string' ? parseFloat(value.replace(/[^0-9.-]+/g, "")) : Number(value);
            if (!isNaN(numValue) && numValue > 0) {
                percepcionesDetalladas.push({
                    name: parsedData.headers[colIndex],
                    value: numValue
                });
                return acc + numValue;
            }
            return acc;
        }, 0);

        const sueldoMensualBase = salarioDiario * 30;

        // Check if the detailed perceptions already contain items that represent the base salary.
        // Common column names for this are 'Sueldo' or 'Vacaciones a tiempo'.
        // If they exist, we assume the provided perception columns represent the full salary,
        // and we should not add the calculated `sueldoMensualBase` to avoid double-counting.
        const hasSalaryComponents = percepcionesDetalladas.some(p => 
            ['sueldo', 'vacaciones a tiempo'].includes(p.name.toLowerCase())
        );

        const totalPercepciones = hasSalaryComponents 
            ? totalOtrasPercepciones 
            : sueldoMensualBase + totalOtrasPercepciones;

        if(totalPercepciones <= 0) return null;

        const nonVariablePerceptionNames = new Set([
            'seguro gmm',
            'seguro de vida',
            'seguro vida',
            'sueldo',
            'vacaciones a tiempo',
            'despensa',
            'horas extras'
        ]);

        const totalPercepcionesVariables = percepcionesDetalladas.reduce((acc, p) => {
            if (!nonVariablePerceptionNames.has(p.name.toLowerCase())) {
                return acc + p.value;
            }
            return acc;
        }, 0);

        const variableSdiComponent = totalPercepcionesVariables / DAYS_IN_MONTH;
        const sdiFijo = salarioDiario * factorIntegracion;
        const sdi = sdiFijo + variableSdiComponent;
        const sdiTopado = Math.min(sdi, uma * SDI_CAP_MULTIPLIER);

        const cuotaFija = uma * (IMSS_RATES.EMPLOYER.FIXED_QUOTA_PCT / 100) * DAYS_IN_MONTH;
        const excedente = sdiTopado > (uma * 3) ? (sdiTopado - (uma * 3)) * (IMSS_RATES.EMPLOYER.EXCESS_QUOTA_PCT / 100) * DAYS_IN_MONTH : 0;
        const prestacionesDinero = sdiTopado * (IMSS_RATES.EMPLOYER.CASH_BENEFITS_PCT / 100) * DAYS_IN_MONTH;
        const gastosMedicos = sdiTopado * (IMSS_RATES.EMPLOYER.MEDICAL_PENSIONERS_PCT / 100) * DAYS_IN_MONTH;
        const invalidezVida = sdiTopado * (IMSS_RATES.EMPLOYER.DISABILITY_LIFE_PCT / 100) * DAYS_IN_MONTH;
        const guarderias = sdiTopado * (IMSS_RATES.EMPLOYER.NURSERY_PCT / 100) * DAYS_IN_MONTH;
        const riesgoTrabajo = sdiTopado * (workRisk / 100) * DAYS_IN_MONTH;
        const imssCosto = cuotaFija + excedente + prestacionesDinero + gastosMedicos + invalidezVida + guarderias + riesgoTrabajo;

        const retiroCosto = sdiTopado * (IMSS_RATES.EMPLOYER.RETIREMENT_PCT / 100) * DAYS_IN_MONTH;
        const cesantiaVejezRate = getCesantiaVejezRate(sdi, uma);
        const cesantiaVejezCosto = sdiTopado * (cesantiaVejezRate / 100) * DAYS_IN_MONTH;

        const infonavitCosto = sdiTopado * (INFONAVIT_RATE_PCT / 100) * DAYS_IN_MONTH;

        const aguinaldoMensual = (aguinaldoDays * salarioDiario) / 12;
        const primaVacacionalMensual = ((salarioDiario * vacationDays) / 12) * primaVacacionalPct;

        const isnCosto = (totalPercepciones + aguinaldoMensual + primaVacacionalMensual) * (isn / 100);

        const costoTotal = totalPercepciones + imssCosto + retiroCosto + cesantiaVejezCosto + infonavitCosto + isnCosto + aguinaldoMensual + primaVacacionalMensual;
        const factor = sueldoMensualBase > 0 ? costoTotal / sueldoMensualBase : 0;

        // --- IMSS Obrero Calculation ---
        const imssObreroExcedente = sdiTopado > (uma * 3) ? (sdiTopado - (uma * 3)) * (IMSS_RATES.EMPLOYEE.EXCESS_QUOTA_PCT / 100) * DAYS_IN_MONTH : 0;
        const imssObreroPrestacionesDinero = sdiTopado * (IMSS_RATES.EMPLOYEE.CASH_BENEFITS_PCT / 100) * DAYS_IN_MONTH;
        const imssObreroGastosMedicos = sdiTopado * (IMSS_RATES.EMPLOYEE.MEDICAL_PENSIONERS_PCT / 100) * DAYS_IN_MONTH;
        const imssObreroInvalidezVida = sdiTopado * (IMSS_RATES.EMPLOYEE.DISABILITY_LIFE_PCT / 100) * DAYS_IN_MONTH;
        const imssObreroCesantiaVejez = sdiTopado * (IMSS_RATES.EMPLOYEE.CESANTIA_VEJEZ_PCT / 100) * DAYS_IN_MONTH;
        const imssObrero = imssObreroExcedente + imssObreroPrestacionesDinero + imssObreroGastosMedicos + imssObreroInvalidezVida + imssObreroCesantiaVejez;
        const imssObreroDetalle = {
            excedente: imssObreroExcedente,
            prestacionesDinero: imssObreroPrestacionesDinero,
            gastosMedicos: imssObreroGastosMedicos,
            invalidezVida: imssObreroInvalidezVida,
            cesantiaVejez: imssObreroCesantiaVejez
        };

        // --- ISR Calculation ---
        const taxableIncome = totalPercepciones;
        const isrBracket = ISR_MONTHLY_TABLE.find(b => taxableIncome >= b.lowerLimit && taxableIncome <= b.upperLimit);
        let isrBruto = 0;
        if (isrBracket) {
            const excessIncome = taxableIncome - isrBracket.lowerLimit;
            isrBruto = (excessIncome * (isrBracket.percentOverExcess / 100)) + isrBracket.fixedQuota;
        }
        const subsidyBracket = SUBSIDY_MONTHLY_TABLE.find(b => taxableIncome >= b.lowerLimit && taxableIncome <= b.upperLimit);
        const subsidioEmpleo = subsidyBracket ? subsidyBracket.subsidy : 0;
        const isr = Math.max(0, isrBruto - subsidioEmpleo);

        // --- Net Salary Calculation ---
        const salarioNeto = totalPercepciones - isr - imssObrero;

        return {
            id: employeeId,
            employeeName,
            totalPercepciones,
            sueldoMensualBase,
            percepcionesDetalladas,
            salarioDiario,
            benefitScheme,
            sdi,
            imss: imssCosto,
            retiro: retiroCosto,
            cesantiaVejez: cesantiaVejezCosto,
            infonavit: infonavitCosto,
            aguinaldoMensual,
            primaVacacionalMensual,
            isn: isnCosto,
            costoTotal,
            factor,
            salarioNeto,
            calculationDetails: {
                sdiTopado, cuotaFija, excedente, prestacionesDinero, gastosMedicos, invalidezVida, guarderias, riesgoTrabajo,
                cesantiaVejezRate, yearsOfService, vacationDays, aguinaldoDays, primaVacacionalPct, factorIntegracion,
                sdiFijo, variableSdiComponent, totalPercepcionesVariables,
                isr,
                subsidioEmpleo,
                imssObrero,
                imssObreroDetalle
            }
        };
    }, [uma, workRisk, isn, employeeIdCol, employeeNameCol, hireDateCol, dailySalaryCol, percepcionColumns, parsedData.headers]);

    useEffect(() => {
        const requiredCols = new Set([employeeIdCol, employeeNameCol, hireDateCol, dailySalaryCol]);
        if (parsedData.rows.length === 0 || requiredCols.size < 4) {
            setResults([]);
            return;
        }

        const newResults = parsedData.rows.map(row => calculateEmployeeResult(row, 'ley', calculationDate)).filter((r): r is CalculationResult => r !== null);
        setResults(newResults);

    }, [parsedData, uma, workRisk, isn, employeeIdCol, employeeNameCol, hireDateCol, dailySalaryCol, calculateEmployeeResult, calculationDate]);

    const handleSchemeChange = useCallback((employeeId: string, newScheme: BenefitSchemeType) => {
        const originalRow = parsedData.rows.find(row => String(row[employeeIdCol]) === employeeId);
        if (!originalRow) return;

        const updatedResult = calculateEmployeeResult(originalRow, newScheme, calculationDate);
        if (!updatedResult) return;

        setResults(prevResults =>
            prevResults.map(res =>
                res.id === employeeId ? updatedResult : res
            )
        );
    }, [parsedData.rows, employeeIdCol, calculateEmployeeResult, calculationDate]);

    const handleReset = useCallback(() => {
        setRawText('');
        setEmployeeIdCol(0);
        setEmployeeNameCol(1);
        setHireDateCol(2);
        setDailySalaryCol(3);
        setResults([]);
    }, []);

    const handleSaveConfig = useCallback(() => {
        const configToSave = { uma, workRisk, isn };
        localStorage.setItem('payrollConfig', JSON.stringify(configToSave));
        setConfigSaved(true);
        setTimeout(() => {
            setConfigSaved(false);
        }, 3000);
    }, [uma, workRisk, isn]);

    const handleExportToExcel = useCallback(() => {
        if (results.length === 0) return;

        const headers = [
            "Código", "Empleado", "Prestaciones", "Sueldo Mensual Base",
            ...percepcionHeaders,
            "Total Percepciones", "Salario Diario", "SDI", "IMSS Patronal", "Retiro Pat.",
            "C y V Pat.", "INFONAVIT Pat.", "Aguinaldo Mensual", "Prima Vac. Mensual",
            "Costo ISN Mensual", "Costo Total Empresa", "Factor de Costo", "Salario Neto"
        ];

        const escapeCsvCell = (cell: any): string => {
            const strCell = String(cell ?? '');
            if (strCell.includes(',') || strCell.includes('"') || strCell.includes('\n')) {
                return `"${strCell.replace(/"/g, '""')}"`;
            }
            return strCell;
        };

        const csvRows = [headers.map(escapeCsvCell).join(',')];

        results.forEach(res => {
            const schemeName = BENEFIT_SCHEMES[res.benefitScheme]?.name || 'N/A';

            const perceptionValues = percepcionHeaders.map(header => {
                const p = res.percepcionesDetalladas.find(pd => pd.name === header);
                return p ? p.value : 0;
            });

            const row = [
                res.id, res.employeeName, schemeName, res.sueldoMensualBase,
                ...perceptionValues,
                res.totalPercepciones, res.salarioDiario, res.sdi, res.imss, res.retiro,
                res.cesantiaVejez, res.infonavit, res.aguinaldoMensual, res.primaVacacionalMensual,
                res.isn, res.costoTotal, res.factor.toFixed(4), res.salarioNeto
            ];

            csvRows.push(row.map(escapeCsvCell).join(','));
        });

        const csvString = csvRows.join('\n');
        const blob = new Blob([`\uFEFF${csvString}`], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", "resultados_costo_factorizado.csv");
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);

    }, [results, percepcionHeaders]);

    const ColumnSelector = ({ label, value, onChange, headers }: { label: string, value: number, onChange: (val: number) => void, headers: string[] }) => (
        <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">{label}</label>
            <select
                value={value}
                onChange={(e) => onChange(parseInt(e.target.value))}
                className="w-full px-3 py-2 bg-slate-50 border border-slate-300 rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            >
                {headers.map((h, i) => <option key={`${label}-${i}`} value={i}>{h}</option>)}
            </select>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-100 p-4 sm:p-6 lg:p-8">
            <div className="max-w-7xl mx-auto">
                <header className="text-center mb-8">
                    <h1 className="text-4xl font-extrabold text-slate-800 tracking-tight">Calculadora de Costo Factorizado</h1>
                    <p className="mt-2 text-lg text-slate-600">Pega los datos de tu nómina desde Excel para calcular el costo total para la empresa.</p>
                </header>

                <main className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    <div className="lg:col-span-1 space-y-8">
                        <ConfigPanel 
                            uma={uma} 
                            setUma={setUma} 
                            workRisk={workRisk} 
                            setWorkRisk={setWorkRisk} 
                            isn={isn} 
                            setIsn={setIsn}
                            onSave={handleSaveConfig}
                            configSaved={configSaved} 
                        />

                        <CalculationDatePanel
                            currentCalculationDate={calculationDate}
                            onApplyDate={setCalculationDate}
                        />

                        <DataTablesPanel
                            isrTable={ISR_MONTHLY_TABLE}
                            subsidyTable={SUBSIDY_MONTHLY_TABLE}
                            cyvTable={CESANTIA_VEJEZ_RATES_2026}
                        />

                        {parsedData.headers.length > 0 && (
                            <div className="bg-white p-6 rounded-xl shadow-md border border-slate-200">
                                <h2 className="text-xl font-bold text-slate-700 mb-4">Mapeo de Columnas</h2>
                                <p className="text-sm text-slate-500 mb-4">Asegúrate que las columnas correctas están seleccionadas para el cálculo.</p>
                                <div className="space-y-4">
                                    <ColumnSelector label="ID del Empleado" value={employeeIdCol} onChange={setEmployeeIdCol} headers={parsedData.headers} />
                                    <ColumnSelector label="Nombre del Empleado" value={employeeNameCol} onChange={setEmployeeNameCol} headers={parsedData.headers} />
                                    <ColumnSelector label="Fecha de Ingreso" value={hireDateCol} onChange={setHireDateCol} headers={parsedData.headers} />
                                    <ColumnSelector label="Sueldo Diario (Base)" value={dailySalaryCol} onChange={setDailySalaryCol} headers={parsedData.headers} />
                                </div>
                            </div>
                        )}

                        <div className="bg-white p-6 rounded-xl shadow-md border border-slate-200">
                             <div className="flex justify-between items-center mb-4">
                                <h2 className="text-xl font-bold text-slate-700">Pegar Datos de Nómina</h2>
                                <button onClick={handleReset} className="flex items-center text-sm text-slate-500 hover:text-blue-600 transition-colors">
                                    <ResetIcon className="h-4 w-4 mr-1" /> Limpiar
                                </button>
                             </div>
                            <textarea
                                value={rawText}
                                onChange={(e) => setRawText(e.target.value)}
                                placeholder="Copia una tabla de Excel (incluyendo encabezados) y pégala aquí..."
                                className="w-full h-48 p-3 bg-slate-50 border border-slate-300 rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-shadow"
                            />
                            <div className="mt-4 p-3 bg-blue-50 border border-blue-200 rounded-lg flex items-start">
                                <InfoIcon className="h-5 w-5 text-blue-500 mr-3 flex-shrink-0 mt-0.5" />
                                <p className="text-sm text-blue-700">
                                    La primera fila debe contener encabezados. Asegúrate de incluir columnas para 'Fecha de Ingreso' y 'Sueldo Diario' para un cálculo preciso del SDI.
                                </p>
                            </div>
                        </div>
                    </div>

                    <div className="lg:col-span-2">
                        {results.length > 0 ? (
                            <>
                                <div className="flex justify-end items-center mb-4 space-x-4">
                                    <button
                                        onClick={handleExportToExcel}
                                        className="flex items-center bg-green-600 text-white font-bold py-2 px-4 rounded-md hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition-all duration-200 ease-in-out text-sm"
                                    >
                                        <DownloadIcon className="h-4 w-4 mr-2" />
                                        Exportar a Excel
                                    </button>
                                    <label htmlFor="layout-checkbox" className="flex items-center text-sm font-medium text-slate-700 cursor-pointer">
                                        <input
                                            id="layout-checkbox"
                                            type="checkbox"
                                            checked={percepcionesLayout === 'horizontal'}
                                            onChange={(e) => setPercepcionesLayout(e.target.checked ? 'horizontal' : 'vertical')}
                                            className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                        />
                                        <span className="ml-2">Mostrar percepciones en columnas</span>
                                    </label>
                                </div>
                                <ResultsTable
                                    results={results}
                                    uma={uma}
                                    workRisk={workRisk}
                                    isn={isn}
                                    layout={percepcionesLayout}
                                    percepcionHeaders={percepcionHeaders}
                                    onSchemeChange={handleSchemeChange}
                                />
                            </>
                        ) : (
                           parsedData.headers.length > 0 && (
                                <div className="flex flex-col items-center justify-center text-center bg-white p-10 rounded-xl shadow-lg border border-slate-200 h-full">
                                    <div className="bg-blue-100 p-4 rounded-full">
                                      <InfoIcon className="h-8 w-8 text-blue-600" />
                                    </div>
                                    <h3 className="mt-4 text-xl font-bold text-slate-700">No hay resultados para mostrar</h3>
                                    <p className="mt-1 text-slate-500 max-w-md">
                                        Verifica el mapeo de columnas. Asegúrate de que las columnas de 'Fecha de Ingreso' y 'Sueldo Diario' contengan datos válidos y que existan columnas de percepciones con valores numéricos.
                                    </p>
                                </div>
                           )
                        )}
                    </div>
                </main>
            </div>
        </div>
    );
}

export default App;

