    { range: '3.01 a 3.50 UMA', rate: 6.36 },
    { range: '3.51 a 4.00 UMA', rate: 6.61 },
    { range: '4.01 UMA en adelante', rate: 7.51 },
];

export const INFONAVIT_RATE_PCT = 5.0;

